var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"밤 바다…… 바람은 좀 쌀쌀해도 꽤 나쁘지 않죠?","JPN":"夜の海……風は少し冷たいけど、なかなか悪くないだろう？","ENG":"The ocean at night... It might be a little chilly, but it’s not so bad, is it?","TWN":"晚上的海邊……雖然風有點涼，但還是很不錯對吧？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"서, 선생님?","JPN":"せ、先生？","ENG":"T-Teacher?!","TWN":"老…老師？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"저는 오늘 같은 날이 아니면 쉽게 할 수 없는 이야기가 있다고 생각해요.","JPN":"今日のような日でないと、簡単に話せない話があるんじゃないかと思ってね。","ENG":"I think now is the perfect opportunity to talk about overlooked things.","TWN":"我覺得今天這種機會很難得，可以將平時不容易說出口的話說出來。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"여행이 끝나고 다시 일상으로 돌아가면, 타이밍을 놓쳐서 쉽게 꺼낼 수 없는 이야기들…….","JPN":"旅行が終わってまた日常に戻ると、チャンスがなくてなかなかできない話とか……","ENG":"The things we don’t talk about once we go back to our daily lives...","TWN":"等旅行結束回到一般日常生活後，那些就很難說出口的話……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 저의 괜한 참견일 뿐일까요?","JPN":"はは、余計なお節介かな？","ENG":"Perhaps I’m being too nosy, ha ha.","TWN":"哈哈，是我太雞婆嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"저라도 괜찮다면, 박스 군의 이야기를 들어보고 싶군요.","JPN":"私でもよければ、ダンボール君の話を聞いてみたいな。","ENG":"But if it’s fine with you, Box... I’d like to hear your story.","TWN":"不介意的話，我想聽聽你的故事。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"저, 사실…… 학교를 다니지 않아요.","JPN":"僕、実は……学校に通ってません。","ENG":"To be frank... I don’t go to school.","TWN":"其實我……沒有在上學。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"등교 거부…… 하고 있거든요.","JPN":"不登校……なんです。","ENG":"I’m... refusing, to be exact.","TWN":"我……拒絕上學。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"누나들이랑 게임을 만들 수 있었던 것도……","JPN":"みんなでゲームを作るのも……","ENG":"The reason why I was able to join the club...","TWN":"所以我才可以和姊姊們一起做遊戲……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"동아리 방에서 철야를 할 수 있었던 것도…… 그래서 가능했던 거고요.","JPN":"部室で徹夜するのも……だからできたんです。","ENG":"And the reason why I was able to pull all-nighters at the club room... was because of that.","TWN":"還可以在社辦熬夜……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이유를 물어봐도 될까요?","JPN":"理由を聞いてもいいかな？","ENG":"May I ask why?","TWN":"我可以問你理由嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"간단해요. 제 얼굴, 여자애처럼 생겼거든요.","JPN":"簡単です。僕の顔、女の子みたいですから。","ENG":"It’s simple. Because I look too feminine.","TWN":"理由很簡單，因為我長得像女生。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"한심하죠? 고작 이런 이유로……","JPN":"情けないでしょう？　たかがこんな理由で……","ENG":"Pathetic, isn’t it? I cower over nothing...","TWN":"很糟糕對吧？因為這個理由就……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"하지만 고작 이런 이유로 반 애들한테 꽤 오랫동안 따돌림당했어요.","JPN":"でも、たかがこんな理由でクラスメイトにかなり長い間いじめられたんです。","ENG":"But because of this irrelevant issue, I was bullied in school for a long time.","TWN":"但因為這個理由，我長期受到班上同學的排擠。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래서 샐러리맨X의 마스크를…….","JPN":"それでサラリーマンXのマスクを……","ENG":"Hence the Salaryman X mask...","TWN":"所以你才會戴著上班族X的面具……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"네. 샐러리맨X는 저한테 용기를 주거든요. 사실 이렇게 선생님과 평범하게 대화를 나눌 수 있는 것도 이 마스크 덕분이에요.","JPN":"はい。サラリーマンXは僕に勇気をくれるんです。実はこうやって先生と普通に話せるのも、このマスクのおかげなんです。","ENG":"Yes. Salaryman X gives me strength. This mask is the sole reason I'm able to talk like this with you, Teacher.","TWN":"沒錯，是上班族X給我勇氣的，現在能夠像這樣和老師正常聊天，也是因為有這個面具。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"하핫, 이상하죠? 마스크가 없으면 말도 잘 못한다는 거……?","JPN":"ははっ、おかしいでしょう？　マスクがないとちゃんと話もできないなんて……","ENG":"Ha ha, I know it sounds strange. Being unable to talk without putting a mask on...","TWN":"哈哈，很詭異吧？竟然沒戴面具就沒辦法說話……？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};